INSERT INTO artikel (id, titel, inhalt, kategorie, autor, erstellt_am, aktualisiert_am) VALUES ('a1', 'Willkommen im Wissensmanagement', 'Das Wissensmanagement ist die zentrale Plattform fuer Dokumentationen, Anleitungen und Fachwissen Ihrer Organisation.', 'Allgemein', 'System', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO artikel (id, titel, inhalt, kategorie, autor, erstellt_am, aktualisiert_am) VALUES ('a2', 'Erste Schritte', 'So nutzen Sie das Wissensmanagement optimal: Durchsuchen Sie vorhandene Artikel, nutzen Sie die Volltextsuche und erstellen Sie neue Artikel.', 'Anleitungen', 'System', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO artikel (id, titel, inhalt, kategorie, autor, erstellt_am, aktualisiert_am) VALUES ('a3', 'Datenschutz im Gesundheitswesen', 'Der Umgang mit personenbezogenen Daten im Gesundheitswesen unterliegt besonderen Anforderungen der DSGVO und des BDSG.', 'Compliance', 'System', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO artikel (id, titel, inhalt, kategorie, autor, erstellt_am, aktualisiert_am) VALUES ('a4', 'IT-Sicherheitsrichtlinien', 'Unsere IT-Sicherheitsrichtlinien umfassen Passwortkomplexitaet, Zwei-Faktor-Authentifizierung und regelmaessige Sicherheitsupdates.', 'IT-Sicherheit', 'System', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
